#include <string.h>
#include <signal.h>

typedef struct { int num; char name[12]; char disp[8]; int catchable; } SigEntry;

/* Test mode: test harness validates directly */

validation.test_code:
static SigEntry table[] = {
    {SIGINT,  "SIGINT",  "TERM", 1},
    {SIGQUIT, "SIGQUIT", "CORE", 1},
    {SIGKILL, "SIGKILL", "TERM", 0},
    {SIGSTOP, "SIGSTOP", "STOP", 0},
    {SIGCHLD, "SIGCHLD", "IGN",  1},
};

#define TABLE_SIZE (sizeof(table)/sizeof(table[0]))

const SigEntry *find_by_num(int num) {
    for (size_t i = 0; i < TABLE_SIZE; i++)
        if (table[i].num == num) return &table[i];
    return NULL;
}

void test_find_by_num_sigint(void) {
    const SigEntry *e = find_by_num(SIGINT);
    TEST_ASSERT_NOT_NULL(e);
    TEST_ASSERT_EQUAL_INT(SIGINT, e->num);
    TEST_ASSERT_EQUAL_INT(1, e->catchable);
}

void test_find_by_num_sigkill(void) {
    const SigEntry *e = find_by_num(SIGKILL);
    TEST_ASSERT_NOT_NULL(e);
    TEST_ASSERT_EQUAL_INT(SIGKILL, e->num);
    TEST_ASSERT_EQUAL_INT(0, e->catchable);
}

void test_find_by_num_sigstop(void) {
    const SigEntry *e = find_by_num(SIGSTOP);
    TEST_ASSERT_NOT_NULL(e);
    TEST_ASSERT_EQUAL_INT(SIGSTOP, e->num);
    TEST_ASSERT_EQUAL_INT(0, e->catchable);
}

void test_find_by_num_not_found(void) {
    const SigEntry *e = find_by_num(99999);
    TEST_ASSERT_NULL(e);
}

int main(void) {
    RUN_TEST(test_find_by_num_sigint);
    RUN_TEST(test_find_by_num_sigkill);
    RUN_TEST(test_find_by_num_sigstop);
    RUN_TEST(test_find_by_num_not_found);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

